const msg = $json.message || {};
const chatId = String(msg.chat?.id || '');
const text = String(msg.text || msg.caption || '').trim();
const hasPhoto = Array.isArray(msg.photo) && msg.photo.length > 0;

const baseUrl = ($env.ROOMY_BASE_URL || 'https://roomy.seudominio.com').replace(/\/$/, '');
const token = $env.ROOMY_N8N_API_TOKEN || 'troque-este-token';

function help() {
  return [
    'Roomy no Telegram',
    '',
    '/vincular SEU_RA - conecta seu Telegram ao Roomy',
    '/tarefas - lista suas tarefas pendentes',
    '/concluir TASK_ID - marca tarefa como concluida',
    '/contas - lista suas contas',
    '/pagar PARTICIPANT_ID - marca sua parte como paga',
    '/estoque - lista estoque da casa e pessoal',
    '',
    'NFC-e: cole o link do QR Code da nota fiscal aqui no chat.',
    'Criar tarefa: /tarefa titulo | local | prioridade | yyyy-mm-dd',
    'Criar conta: /conta titulo | total | yyyy-mm-dd | userId:valor,userId:valor',
  ].join('\n');
}

async function callRoomy(path, options = {}) {
  const response = await fetch(`${baseUrl}${path}`, {
    method: options.method || 'GET',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${token}`,
    },
    body: options.body ? JSON.stringify(options.body) : undefined,
  });

  const raw = await response.text();
  let data;
  try {
    data = raw ? JSON.parse(raw) : {};
  } catch {
    data = { raw };
  }

  if (!response.ok) {
    throw new Error(data.error || `Roomy HTTP ${response.status}`);
  }

  return data;
}

function money(value) {
  return Number(value || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
}

function shortId(id) {
  return String(id || '').slice(0, 8);
}

try {
  if (!chatId) {
    return [{ json: { chatId, reply: 'Nao consegui identificar este chat.' } }];
  }

  if (hasPhoto && !text) {
    return [{ json: { chatId, reply: 'Recebi a foto do QR. Para esta versao, envie tambem o link decodificado da NFC-e. Depois podemos plugar um node de leitura de QR por imagem.' } }];
  }

  if (!text || /^\/start/i.test(text) || /^\/help/i.test(text)) {
    return [{ json: { chatId, reply: help() } }];
  }

  const vincular = text.match(/^\/vincular\s+(.+)$/i);
  if (vincular) {
    const data = await callRoomy('/api/n8n/telegram/link', {
      method: 'POST',
      body: { ra: vincular[1].trim(), telegramChatId: chatId },
    });
    return [{ json: { chatId, reply: `Pronto, ${data.user.name}. Telegram vinculado ao Roomy.` } }];
  }

  if (/^\/tarefas/i.test(text)) {
    const data = await callRoomy(`/api/n8n/tasks?telegramChatId=${encodeURIComponent(chatId)}`);
    const tasks = data.tasks || [];
    if (!tasks.length) return [{ json: { chatId, reply: 'Voce nao tem tarefas pendentes.' } }];

    const lines = tasks.map((t, index) => {
      const due = t.due_date ? ` vence ${t.due_date}` : ' sem vencimento';
      return `${index + 1}. ${t.title} (${t.room || 'Geral'}) - ${t.priority || 'media'} - ${due}\nID: ${t.id}`;
    });
    return [{ json: { chatId, reply: `Tarefas pendentes:\n\n${lines.join('\n\n')}\n\nUse /concluir TASK_ID` } }];
  }

  const concluir = text.match(/^\/concluir\s+([a-f0-9-]+)/i);
  if (concluir) {
    await callRoomy('/api/n8n/tasks', {
      method: 'POST',
      body: { action: 'complete', telegramChatId: chatId, taskId: concluir[1] },
    });
    return [{ json: { chatId, reply: 'Tarefa marcada como concluida.' } }];
  }

  const novaTarefa = text.match(/^\/tarefa\s+(.+)$/i);
  if (novaTarefa) {
    const [title, room = 'Geral', priority = 'media', dueDate = null] = novaTarefa[1].split('|').map(s => s.trim());
    const data = await callRoomy('/api/n8n/tasks', {
      method: 'POST',
      body: { action: 'create', telegramChatId: chatId, title, room, priority, dueDate },
    });
    return [{ json: { chatId, reply: `Tarefa criada. ID: ${data.taskId}` } }];
  }

  if (/^\/contas/i.test(text)) {
    const data = await callRoomy(`/api/n8n/bills?telegramChatId=${encodeURIComponent(chatId)}`);
    const bills = data.bills || [];
    if (!bills.length) return [{ json: { chatId, reply: 'Nenhuma conta encontrada para voce.' } }];

    const lines = bills.map((b, index) => {
      const status = b.paid ? 'paga' : 'pendente';
      return `${index + 1}. ${b.title} - ${money(b.amount)} - ${status} - vence ${b.due_date}\nparticipantId: ${b.participant_id}`;
    });
    return [{ json: { chatId, reply: `Suas contas:\n\n${lines.join('\n\n')}\n\nUse /pagar PARTICIPANT_ID` } }];
  }

  const pagar = text.match(/^\/pagar\s+([a-f0-9-]+)/i);
  if (pagar) {
    await callRoomy('/api/n8n/bills', {
      method: 'POST',
      body: { action: 'mark-paid', telegramChatId: chatId, participantId: pagar[1] },
    });
    return [{ json: { chatId, reply: 'Conta marcada como paga.' } }];
  }

  const novaConta = text.match(/^\/conta\s+(.+)$/i);
  if (novaConta) {
    const [title, totalRaw, dueDateRaw, involvedRaw = ''] = novaConta[1].split('|').map(s => s.trim());
    const total = Number(String(totalRaw).replace(',', '.'));
    const involved = involvedRaw
      ? involvedRaw.split(',').map(part => {
          const [userId, amount] = part.split(':').map(s => s.trim());
          return { userId, amount: Number(String(amount).replace(',', '.')) };
        })
      : undefined;

    await callRoomy('/api/n8n/bills', {
      method: 'POST',
      body: { action: 'create', telegramChatId: chatId, title, total, dueDate: dueDateRaw || undefined, involved },
    });
    return [{ json: { chatId, reply: `Conta criada: ${title} (${money(total)}).` } }];
  }

  if (/^\/estoque/i.test(text)) {
    const data = await callRoomy(`/api/n8n/stock?telegramChatId=${encodeURIComponent(chatId)}`);
    const stock = data.stock || [];
    if (!stock.length) return [{ json: { chatId, reply: 'Estoque vazio.' } }];

    const low = stock.filter(i => Number(i.quantity) <= Number(i.min_quantity));
    const source = low.length ? low : stock.slice(0, 20);
    const title = low.length ? 'Itens baixos/esgotados:' : 'Estoque:';
    const lines = source.map((i, index) => `${index + 1}. ${i.name} - ${i.quantity} ${i.unit} (min ${i.min_quantity})\nID: ${i.id}`);
    return [{ json: { chatId, reply: `${title}\n\n${lines.join('\n\n')}` } }];
  }

  if (/^https?:\/\//i.test(text)) {
    const data = await callRoomy('/api/n8n/nfce', {
      method: 'POST',
      body: { telegramChatId: chatId, url: text },
    });

    const nfce = data.nfce_data;
    if (!nfce) return [{ json: { chatId, reply: 'Nao consegui processar essa NFC-e.' } }];

    const items = (nfce.itens || []).slice(0, 10).map((item, index) => `${index + 1}. ${item.descricao} - ${money(item.valor_total)}`);
    return [{ json: { chatId, reply: `NFC-e lida:\n${nfce.estabelecimento || 'Estabelecimento'}\nTotal: ${money(nfce.valor_pagar)}\nItens: ${nfce.total_itens}\n\n${items.join('\n')}\n\nPara criar a conta, use:\n/conta ${nfce.estabelecimento || 'Compra'} | ${nfce.valor_pagar || 0} | ${new Date().toISOString().slice(0, 10)}` } }];
  }

  return [{ json: { chatId, reply: `Comando nao reconhecido.\n\n${help()}` } }];
} catch (error) {
  return [{ json: { chatId, reply: `Erro: ${error.message}` } }];
}

const body = $json.body || $json;
const event = body.event || 'roomy.event';
const payload = body.payload || {};
const chatId = payload.telegramChatId || payload.chatId || '';

let reply = `Roomy: ${event}`;
if (payload.title) reply += `\n${payload.title}`;
if (payload.taskId) reply += `\nTarefa: ${payload.taskId}`;
if (payload.billId) reply += `\nConta: ${payload.billId}`;
if (payload.transactionId) reply += `\nTransacao: ${payload.transactionId}`;

return [{ json: { chatId, reply, shouldSend: Boolean(chatId), response: { ok: true } } }];
